import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import NavigationBar from './components/NavigationBar';
import DiscountChart from './components/DiscountChart';

// Import other components (assuming they exist)
import Home from './components/Home';
import DeltaDiscounts from './components/DeltaDiscounts';
import PercentDiscounts from './components/PercentDiscounts';
import Arbs from './components/Arbs';
import Apy from './components/Apy';
import Leagues from './components/Leagues';
import Gas from './components/Gas';
import Buy from './components/Buy';

function App() {
  const chartConfigs = [
    { tableName: 'pMAXI - DiscountChart', title: 'pMaxi Ⓜ️' },
    { tableName: 'pDECI - DiscountChart', title: 'pDECI 🛡️' },
    { tableName: 'pLUCKY - DiscountChart', title: 'pLUCKY 🍀' },
    { tableName: 'pTRIO - DiscountChart', title: 'pTRIO 🎲' },
    { tableName: 'pBASE - DiscountChart', title: 'pBASE 🟠' },
  ];

  return (
    <Router>
      <div className="App">
        <NavigationBar />
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/delta-discounts" element={<DeltaDiscounts />} />
          <Route path="/percent-discounts" element={<PercentDiscounts />} />
          <Route path="/arbs" element={<Arbs />} />
          <Route path="/apy" element={<Apy />} />
          <Route path="/leagues" element={<Leagues />} />
          <Route path="/gas" element={<Gas />} />
          <Route path="/buy" element={<Buy />} />
        </Routes>
        <div>
          {chartConfigs.map((config, index) => (
            <DiscountChart 
              key={index}
              tableName={config.tableName}
              title={config.title}
            />
          ))}
        </div>
      </div>
    </Router>
  );
}

export default App;
